from ag2.tools import tool

@tool
def search_web(query: str, num_results: int = 5) -> str:
    """Search the web for recent information"""
    from serpapi import GoogleSearch
    params = {
        "q": query,
        "num": num_results,
        "api_key": os.getenv("SERPAPI_KEY"),
        "tbs": "qdr:m6"  # past 6 months
    }
    search = GoogleSearch(params)
    results = search.get_dict()
    return str([r['title'] + ': ' + r['link'] for r in results['organic_results']])

searcher = AssistantAgent(
    name="Searcher",
    llm_config={"config_list": [{"model": "gpt-4o", "api_key": os.getenv("OPENAI_API_KEY")}]},
    tools=[search_web]
)

def verify_source(url: str, claim: str) -> dict:
    """Score source credibility and claim accuracy"""
    domain_scores = {
        'nytimes.com': 0.95, 'wsj.com': 0.93, 'wikipedia.org': 0.75,
        'breitbart.com': 0.45, 'infowars.com': 0.20
    }
    domain = url.split('/')[2]
    credibility = domain_scores.get(domain, 0.5)

    # Recency check
    import requests
from bs4 import BeautifulSoup
import dateutil.parser

    try:
        resp = requests.get(url)
        soup = BeautifulSoup(resp.content, 'html.parser')
        date_str = soup.find('time') or soup.find('date')
        if date_str:
            pub_date = dateutil.parser.parse(date_str.get('datetime'))
            recency_score = max(0, 1 - (datetime.now() - pub_date).days / 180)
        else:
            recency_score = 0.5
    except:
        recency_score = 0.5

    return {
        'credibility': credibility,
        'recency': recency_score,
        'overall_score': (credibility * 0.6 + recency_score * 0.4)
    }

