@vex_client.hook(policy="source_verification")
def verify_search_results(message: str, agent_name: str, context: dict) -> str:
    """Verify search results before analysis phase"""
    if 'http' not in message:
        return message

    urls = vex.extract_urls(message)
    verified_sources = []

    for url in urls[:5]:  # Top 5 sources
        score = verify_source(url, context.get('query', ''))
        if score['overall_score'] > 0.7:
            verified_sources.append(f"✅ {url} (score: {score['overall_score']:.2f})")
        else:
            verified_sources.append(f"❌ {url} (score: {score['overall_score']:.2f} - LOW CREDIBILITY)")

    context['verified_sources'] = verified_sources
    return f"VERIFIED SOURCES:\n{"".join(verified_sources)}\n\nOriginal: {message}" 

searcher.register_message([verify_search_results])
